#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100
#define MAX_FRIENDS 100

int min(int a, int b) { return a < b ? a : b; }

int* bfs(int **graph, int N, int start) {
    int *dist = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) dist[i] = INT_MAX;
    dist[start] = 0;
    int *queue = (int *)malloc(N * sizeof(int));
    int front = 0, rear = 0;
    queue[rear++] = start;
    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < N; v++) {
            if (graph[u][v] == 1 && dist[v] == INT_MAX) {
                dist[v] = dist[u] + 1;
                queue[rear++] = v;
            }
        }
    }
    free(queue);
    return dist;
}

