// COMPLETE, COMPILABLE Java code
import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] graph = new int[N][N];
            for (int i = 0; i < N; i++) {
                int M = sc.nextInt();
                for (int j = 0; j < M; j++) {
                    int friend = sc.nextInt() - 1;
                    graph[i][friend] = 1;
                }
            }
            double min_avg = Double.MAX_VALUE;
            int most_popular = -1;
            for (int i = 0; i < N; i++) {
                int[] dist = bfs(graph, N, i);
                double avg = 0.0;
                for (int j = 0; j < N; j++) avg += dist[j];
                avg /= N;
                if (avg < min_avg) {
                    min_avg = avg;
                    most_popular = i + 1;
                }
            }
            System.out.println(most_popular + " " + String.format("%.6f", min_avg));
        }
    }

    public static int[] bfs(int[][] graph, int N, int start) {
        int[] dist = new int[N];
        for (int i = 0; i < N; i++) dist[i] = Integer.MAX_VALUE;
        dist[start] = 0;
        Queue<Integer> q = new LinkedList<>();
        q.add(start);
        while (!q.isEmpty()) {
            int u = q.poll();
            for (int v = 0; v < N; v++) {
                if (graph[u][v] == 1 && dist[v] == Integer.MAX_VALUE) {
                    dist[v] = dist[u] + 1;
                    q.add(v);
                }
            }
        }
        return dist;
    }
}

