function bfs(graph, N, start) {
    let dist = new Array(N).fill(Infinity);
    dist[start] = 0;
    let q = [start];
    while (q.length > 0) {
        let u = q.shift();
        for (let v = 0; v < N; v++) {
            if (graph[u][v] == 1 && dist[v] == Infinity) {
                dist[v] = dist[u] + 1;
                q.push(v);
            }
        }
    }
    return dist;
